import{_ as e,c as t,o as r,V as o}from"./chunks/framework.1sOznGPE.js";const g=JSON.parse('{"title":"Vue3响应式数据原理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/interview/vue/vue/vue3响应式数据原理.md","filePath":"guide/interview/vue/vue/vue3响应式数据原理.md","lastUpdated":1719242077000}'),a={name:"guide/interview/vue/vue/vue3响应式数据原理.md"},_=o('<h1 id="vue3响应式数据原理" tabindex="-1">Vue3响应式数据原理 <a class="header-anchor" href="#vue3响应式数据原理" aria-label="Permalink to &quot;Vue3响应式数据原理&quot;">​</a></h1><p>Vue3.x改用<code>Proxy</code>替代Object.defineProperty。因为Proxy可以直接监听对象和数组的变化，并且有多达13种拦截方法。并且作为新标准将受到浏览器厂商重点持续的性能优化</p><p><strong>Proxy只会代理对象的第一层，那么Vue3又是怎样处理这个问题的呢？（拓展）</strong></p><p>判断当前Reflect.get的返回值是否为Object，如果是则再通过<code>reactive</code>方法做代理， 这样就实现了深度观测。</p><p><strong>监测数组的时候可能触发多次get/set，那么如何防止触发多次呢？（拓展）</strong></p><p>我们可以判断key是否为当前被代理对象target自身属性，也可以判断旧值与新值是否相等，只有满足以上两个条件之一时，才有可能执行trigger。</p>',6),c=[_];function i(n,s,u,d,p,v){return r(),t("div",null,c)}const f=e(a,[["render",i]]);export{g as __pageData,f as default};
